# Skeptic: only packet-taught patterns; explicit I/O contract
def assess(record: dict) -> str:
    required = {'target_ms', 'stimulus', 'environment', 'source', 'case_id', 'observed_ms', 'response', 'owner'}
    missing = sorted(required - record.keys())
    if missing:
        return "MISSING:" + ",".join(missing)
    if record["observed_ms"] < record["target_ms"]:
        return 'PASS'
    return 'REJECT_QA_SCENARIO'

