adverse = {"case_id": 'CASO-SYN-1A-ADV', 'source': 'ops', 'stimulus': '100 req/s', 'environment': 'peak', 'response': 'serve', 'observed_ms': 500, 'target_ms': 300, 'owner': ''}
missing = {k: valid[k] for k in valid if k != 'owner'}
print(assess(valid))
print(assess(adverse))
print(assess(missing))

