# Skeptic: only packet-taught patterns; explicit I/O contract
def assess(record: dict) -> str:
    required = {"case_id", "contexts", "translations"}
    missing = sorted(required - record.keys())
    if missing:
        return "MISSING:" + ",".join(missing)
    return "PASS" if not (bool(record["contexts"]["intake"] & record["contexts"]["er"])) else "SPLIT_CONTEXTS"

valid = {"case_id": "CASO-LIM-040-3A", **{"contexts":{"intake":{"case"},"er":{"record","score"}},"translations":{"case":"record"}}}
invalid = {"case_id": "CASO-LIM-040-3A", **{"contexts":{"intake":{"case"},"er":{"case","score"}},"translations":{}}}
incomplete = {**valid}
incomplete.pop("translations")
results = (assess(valid), assess(invalid), assess(incomplete))
print(*results)
print(assess(valid))
missing = {k: valid[k] for k in valid if k != 'translations'}
print(assess(missing))

